mapper.update:
	/* tms-master-owner-sql-oracle.xml - updateTOrderMstOw */
	UPDATE 	TT_MST_OW
	SET		ZIPCODE      		= #{zipcode}
			,UPDATEURKEY  		= #{surkey}
			,UPDATEDATE   		= #{sysdate}
			,TEL2         		= #{tel2}
			,TEL1         		= #{tel1}
			,STATE        		= #{state}
			,OWNAME       		= #{owname}
			,REGNO       		= #{regno}
	        ,BUSINESSTYPE   	= #{businesstype}
	        ,BUSINESSCATEGORY	= #{businesscategory} 
			,FAX          		= #{fax}
			,COUNTRYCODE  		= #{countrycode}
			,CONTACT      		= #{contact}
			,CITY         		= #{city}
			,CEO          		= #{ceo}
			,ADDRESS2     		= #{address2}
			,ADDRESS1     		= #{address1}
			,DIMENSION_UOM		= #{dimension_uom}
			,WEIGHT_UOM			= #{weight_uom}
			,UDF1				= #{udf1}
			,UDF2				= #{udf2}
			,UDF3				= #{udf3}
			,BOXTYPE			= #{boxtype}
			,LAKEY				= #{lakey}
            ,CURRTYP			= #{currtyp}
            ,BRCDTYP			= #{brcdtyp}
            ,DELSTTVRFTYP		= #{delsttvrftyp}
            ,ALWMXDYN			= #{alwmxdyn}
            ,EMAIL				= #{email}
            ,WEBURL				= #{weburl}
            ,UOMTYP				= #{uomtyp}
            ,LOGGRPCD			= #{loggrpcd}
            ,CUSTTYPE			= #{custtype}
            ,STTCD				= #{sttcd}
            ,ADDRID				= #{addrid}
            ,BILLTOCUSTCD   	= #{billtocustcd}
			,DELYN 				= #{delyn}
	WHERE	OWKEY = #{owkey}

mapper.delete:
/* tms-master-center-sql-oracle.xml - deleteTOrderMstOw */
UPDATE  TT_MST_OW
SET      DELYN 				= 'Y'
		,CLOSDATE		= #{sysdate}
WHERE	OWKEY = #{owkey}
